const TEAM_MAP = {
  '<YOUR_SLACK_USER_ID>': { platform_id: '<PLATFORM_USER_ID>', name: '<OPERATOR_NAME>', role: 'operator' },
  '<YOUR_SLACK_USER_ID_2>': { platform_id: '<PLATFORM_USER_ID_2>', name: '<OPERATOR_NAME_2>', role: 'operator' }
};

const slackUserId  = String($('Start').first().json.slack_user_id    || '').trim();
const dealId       = String($('Start').first().json.deal_id          || '').trim();
const slackChannel = String($('Start').first().json.slack_channel_id || '').trim();
const slackTs      = String($('Start').first().json.slack_thread_ts  || '').trim();
const authToken    = String($('Platform Authentication').first().json.data.access_token || '').trim();

if (!slackUserId) throw new Error('slack_user_id is required');
if (!dealId)      throw new Error('deal_id is required');
if (!authToken)   throw new Error('access_token is required');

const sender = TEAM_MAP[slackUserId];
if (!sender) throw new Error(`Slack user ${slackUserId} not found in TEAM_MAP.`);

const base = ($vars.platform_api_base_url || 'https://api.example.com').replace(/\/+$/, '');

return [{
  json: {
    slack_user_id:     slackUserId,
    deal_id:           dealId,
    auth_token:        authToken,
    slack_channel_id:  slackChannel,
    slack_thread_ts:   slackTs,
    sender_platform_id:      sender.platform_id,
    sender_name:       sender.name,
    sender_role:       sender.role,
    _base:             base,
    _impersonate_url:  `${base}/api/int/users/${sender.platform_id}/impersonate`,
    _app_endpoint:     `${base}/api/int/applications/${dealId}`,
    _alias_endpoint:   `${base}/api/int/users/${sender.platform_id}/email_addresses`,
    _email_endpoint:   `${base}/api/int/communication/emails`,
    _notes_endpoint:   `${base}/api/int/notes`,
    _history_endpoint: `${base}/api/int/communication_logs/filter?type=email&application_ids%5B%5D=${dealId}`
  }
}];

// Extrae el token impersonado y lo propaga hacia adelante
const imp    = $('Impersonate Request').first().json;
const sender = $('Resolve Sender').first().json;

const impToken = String(
  imp.data?.access_token ||
  imp.access_token ||
  sender.auth_token ||
  ''
).trim();

if (!impToken) throw new Error('Impersonation failed — no token returned');

return [{
  json: {
    ...sender,
    imp_token: impToken
  }
}];

// ============================================================
// Resolve Template
// Determina dinámicamente qué template usar basado en:
// 1. requested_amount → Streamline (≤$150K) vs Traditional (>$150K)
// 2. historial de emails del sender → Initial vs 1st vs 2nd follow-up
// ============================================================

const TEMPLATES = {
  streamline_initial:   '<UUID>',
  traditional_initial:  '<UUID>',
  followup_1st:         '<UUID>',
  followup_2nd:         '<UUID>'
};

const sender     = $('Extract Imp Token').first().json;
const appData    = $('GET Application').first().json.data;
const history    = $('GET Email History').first().json.data || [];

if (!appData) throw new Error('GET Application returned no data');

// --- Datos del deal ---
const prequal          = appData.prequalification || {};
const requestedAmount  = Number(prequal.requested_amount || 0);
const missingStips     = (appData.stips || []).filter(s => !s.is_finished);
const contactEmail     = (appData.personal_information || {}).email_address || '';
const businessName     = (appData.business || {}).business_legal_name || appData.application_name || '';
const firstName        = (appData.personal_information || {}).first_name || 'there';

// --- Verificar si hay docs faltantes ---
if (missingStips.length === 0) {
  return [{
    json: {
      ...sender,
      _skip: true,
      _skip_reason: 'No missing documents for this deal',
      _business_name: businessName
    }
  }];
}

// --- Determinar Streamline vs Traditional ---
const isStreamline = requestedAmount > 0 && requestedAmount <= 150000;

// --- Contar emails previos del sender en este deal ---
const INTERVAL_MINUTES = 2880; // 48h

const senderEmails = history.filter(e =>
  e.data?.status === 'sent' &&
  String(e.data?.sender?.id) === String(sender.sender_platform_id)
).sort((a, b) =>
  new Date(b.data.created_at) - new Date(a.data.created_at)
);

const emailCount       = senderEmails.length;
const lastEmail        = senderEmails[0] || null;
const minutesSinceLast = lastEmail
  ? Math.floor((Date.now() - new Date(lastEmail.data.created_at).getTime()) / 60000)
  : null;
const intervalOk = lastEmail ? minutesSinceLast >= INTERVAL_MINUTES : true;

// --- Seleccionar template ---
let templateId, templateType;

if (emailCount === 0) {
  templateId   = isStreamline ? TEMPLATES.streamline_initial : TEMPLATES.traditional_initial;
  templateType = isStreamline ? 'streamline_initial' : 'traditional_initial';
} else if (emailCount === 1) {
  templateId   = TEMPLATES.followup_1st;
  templateType = 'followup_1st';
} else {
  templateId   = TEMPLATES.followup_2nd;
  templateType = 'followup_2nd';
}

const base = sender._base;

return [{
  json: {
    ...sender,
    _skip:              false,
    _interval_ok:       intervalOk,
    _minutes_since_last: minutesSinceLast,
    _email_count:       emailCount,
    _template_id:       templateId,
    _template_type:     templateType,
    _is_streamline:     isStreamline,
    _requested_amount:  requestedAmount,
    _contact_email:     contactEmail,
    _business_name:     businessName,
    _first_name:        firstName,
    _missing_stips:     missingStips.map(s => s.name),
    _missing_count:     missingStips.length,
    _template_endpoint: `${base}/api/int/email/template/${templateId}`
  }
}];

// ============================================================
// Build Payload
// Ensambla el payload final con:
// - subject + body del template oficial de Platform
// - alias correcto del sender por lender del deal
// - sender_user_id del impersonado
// ============================================================

const resolved   = $('Resolve Template').first().json;
const templateData = $('GET Platform Template').first().json.data || {};
const aliasData  = $('GET Sender Aliases').first().json;
const appData    = $('GET Application').first().json.data;

// --- Resolver alias por lender del deal ---
const dealClientName = (appData.client?.name || '').trim().toLowerCase();
const aliases        = aliasData.aliases || [];
const primary        = aliasData.primary || {};

let matchedAlias = null;
if (dealClientName) {
  matchedAlias = aliases.find(a =>
    (a.client?.name || '').trim().toLowerCase() === dealClientName
  );
}

const fromEmail = matchedAlias ? matchedAlias.email : (primary.email || '');
const fromType  = matchedAlias ? 'alias' : 'gmail_primary';

if (!fromEmail) throw new Error('No email alias found for sender ' + resolved.sender_name);

// --- Subject y body del template ---
const subject = templateData.subject || `${resolved._business_name} — Documents Required`;
const body    = templateData.body    || '';

if (!body) throw new Error(`Template ${resolved._template_id} returned empty body`);

// --- Payload final ---
const appId = resolved.deal_id;

const emailPayload = {
  applications:            { [appId]: resolved._contact_email },
  subject,
  body,
  email_template_id:       resolved._template_id,
  preferred_email_address: {
    type:         fromType,
    value:        fromEmail,
    send_as_bulk: false
  },
  sender_user_id: resolved.sender_platform_id
};

const noteComment = [
  `Missing docs email enviado a ${resolved._contact_email}`,
  `por ${resolved.sender_name} (${resolved.sender_role}).`,
  `Template: ${resolved._template_type}.`,
  `Docs: ${resolved._missing_stips.join(', ')}.`,
  `Alias: ${fromEmail}.`,
  `Ejecución: ${$execution.id}.`
].join(' ');

return [{
  json: {
    ...resolved,
    _from_email:      fromEmail,
    _from_type:       fromType,
    _subject:         subject,
    _email_payload:   emailPayload,
    _note_comment:    noteComment
  }
}];

const p = $json;
const isSkip     = p._skip;
const noInterval = !p._interval_ok;

let msg;
if (isSkip) {
  msg = `✅ No missing documents for *${p._business_name}* — email not sent.`;
} else if (noInterval) {
  msg = `⏳ Email not sent for *${p._business_name}* — interval not completed (${p._minutes_since_last} min since last, need 2880).`;
} else {
  msg = `⚠️ Email skipped for unknown reason.`;
}

return [{ json: { ...p, _slack_response: msg, _sent: false } }];
